import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { 
  TrendingUp, 
  AlertTriangle, 
  Clock, 
  Target, 
  Lightbulb,
  Plus,
  Download,
  Copy,
  CheckCircle,
  X
} from 'lucide-react';
import { analyticsApi, notesApi } from '../api/analytics';
import Card from './Card';

const METRICS = [
  { key: 'registered_onboarded', label: 'Registered Onboarded' },
  { key: 'linked_accounts', label: 'Linked Accounts' },
  { key: 'total_advance_applications', label: 'Total Advance Applications' },
  { key: 'total_advance_applicants', label: 'Total Advance Applicants' },
  { key: 'total_micro_financing_applications', label: 'Total Micro Financing Applications' },
  { key: 'total_micro_financing_applicants', label: 'Total Micro Financing Applicants' },
  { key: 'total_personal_finance_application', label: 'Total Personal Finance Application' },
  { key: 'total_personal_finance_applicants', label: 'Total Personal Finance Applicants' }
];

const PRIORITY_COLORS = {
  high: 'border-red-200 bg-red-50',
  medium: 'border-yellow-200 bg-yellow-50',
  low: 'border-green-200 bg-green-50'
};

const TYPE_ICONS = {
  opportunity: TrendingUp,
  risk: AlertTriangle,
  timing: Clock,
  channel: Target,
  creative: Lightbulb
};

const MarketingStrategyAdvisor: React.FC = () => {
  const [selectedMetric, setSelectedMetric] = useState('total_advance_applicants');
  const [selectedWeeks, setSelectedWeeks] = useState('all');
  const [selectedMonths, setSelectedMonths] = useState('all');
  const [checklist, setChecklist] = useState<any[]>([]);
  const [showChecklist, setShowChecklist] = useState(false);

  const queryClient = useQueryClient();

  const { data, isLoading, error } = useQuery({
    queryKey: ['strategy-advisor', selectedMetric, selectedWeeks, selectedMonths],
    queryFn: () => analyticsApi.getStrategyAdvisor({
      metric: selectedMetric,
      weeks: selectedWeeks,
      months: selectedMonths
    })
  });

  const createNoteMutation = useMutation({
    mutationFn: notesApi.create,
    onSuccess: () => {
      queryClient.invalidateQueries(['notes']);
    }
  });

  const handleCreateNote = (insight: any) => {
    const noteData = {
      title: insight.title,
      content: `Evidence: ${JSON.stringify(insight.evidence)}\n\nRecommendation: ${insight.recommendation}`,
      tags: ['advisor', 'auto', insight.type],
      report_date: new Date().toISOString().split('T')[0]
    };

    createNoteMutation.mutate(noteData);
  };

  const handleAddToChecklist = (insight: any) => {
    const taskId = `task-${insight.id}`;
    const existingTask = checklist.find(item => item.id === taskId);
    
    if (!existingTask) {
      const newTask = {
        id: taskId,
        label: `Action: ${insight.title}`,
        details: insight.recommendation,
        priority: insight.priority,
        owner: null,
        due: null,
        completed: false
      };
      setChecklist(prev => [...prev, newTask]);
    }
  };

  const handleRemoveFromChecklist = (taskId: string) => {
    setChecklist(prev => prev.filter(item => item.id !== taskId));
  };

  const handleToggleTaskComplete = (taskId: string) => {
    setChecklist(prev => 
      prev.map(item => 
        item.id === taskId ? { ...item, completed: !item.completed } : item
      )
    );
  };

  const exportChecklistCSV = () => {
    const headers = ['Task', 'Priority', 'Details', 'Owner', 'Due Date', 'Status'];
    const rows = checklist.map(item => [
      item.label,
      item.priority,
      item.details,
      item.owner || 'Unassigned',
      item.due || 'No due date',
      item.completed ? 'Completed' : 'Pending'
    ]);

    const csvContent = [headers, ...rows]
      .map(row => row.map(cell => `"${cell}"`).join(','))
      .join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `marketing-strategy-checklist-${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    window.URL.revokeObjectURL(url);
  };

  const copyChecklistToClipboard = () => {
    const text = checklist
      .map(item => `□ ${item.label} (${item.priority.toUpperCase()})`)
      .join('\n');
    navigator.clipboard.writeText(text);
  };

  const getTypeIcon = (type: string) => {
    const Icon = TYPE_ICONS[type as keyof typeof TYPE_ICONS] || Lightbulb;
    return Icon;
  };

  return (
    <div className="space-y-6">
      <Card title="Marketing Strategy Advisor">
        <div className="space-y-6">
          {/* Controls */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Select Metric
              </label>
              <select
                value={selectedMetric}
                onChange={(e) => setSelectedMetric(e.target.value)}
                className="w-full p-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500"
              >
                {METRICS.map(metric => (
                  <option key={metric.key} value={metric.key}>
                    {metric.label}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Weeks
              </label>
              <select
                value={selectedWeeks}
                onChange={(e) => setSelectedWeeks(e.target.value)}
                className="w-full p-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500"
              >
                <option value="all">All Weeks</option>
                <option value="1">Week 1</option>
                <option value="2">Week 2</option>
                <option value="3">Week 3</option>
                <option value="4">Week 4</option>
                <option value="5">Week 5</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Months
              </label>
              <select
                value={selectedMonths}
                onChange={(e) => setSelectedMonths(e.target.value)}
                className="w-full p-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500"
              >
                <option value="all">All Months</option>
              </select>
            </div>
          </div>

          {/* Loading */}
          {isLoading && (
            <div className="flex justify-center py-8">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-500"></div>
            </div>
          )}

          {/* Error */}
          {error && (
            <div className="bg-red-50 border border-red-200 rounded-md p-4">
              <p className="text-red-800">Error loading insights: {(error as Error)?.message || 'Unknown error'}</p>
            </div>
          )}

          {/* No Data */}
          {data && (!data.insights || data.insights.length === 0) && (
            <div className="text-center py-12">
              <div className="bg-gray-100 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4">
                <Target className="h-8 w-8 text-gray-400" />
              </div>
              <h3 className="text-lg font-medium text-gray-900 mb-2">No Data Available</h3>
              <p className="text-gray-500 mb-4">We need more data to generate marketing insights.</p>
              <button className="bg-blue-500 text-white px-4 py-2 rounded-md hover:bg-blue-600">
                Go to Data Entry
              </button>
            </div>
          )}

          {/* Insights */}
          {data && data.insights && data.insights.length > 0 && (
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-lg font-semibold text-gray-900">
                  Strategic Insights ({data.insights.length})
                </h3>
                <button
                  onClick={() => setShowChecklist(!showChecklist)}
                  className="flex items-center space-x-2 text-blue-600 hover:text-blue-800"
                >
                  <Target className="h-4 w-4" />
                  <span>Checklist ({checklist.length})</span>
                </button>
              </div>

              {/* Insights Feed */}
              <div className="space-y-4">
                {data.insights.map((insight: any) => {
                  const Icon = getTypeIcon(insight.type);
                  const isInChecklist = checklist.some(item => item.id === `task-${insight.id}`);
                  
                  return (
                    <div 
                      key={insight.id}
                      className={`border rounded-lg p-4 ${PRIORITY_COLORS[insight.priority as keyof typeof PRIORITY_COLORS]}`}
                    >
                      <div className="flex items-start space-x-3">
                        <div className={`p-2 rounded-lg ${
                          insight.type === 'opportunity' ? 'bg-green-100 text-green-600' :
                          insight.type === 'risk' ? 'bg-red-100 text-red-600' :
                          insight.type === 'timing' ? 'bg-blue-100 text-blue-600' :
                          'bg-gray-100 text-gray-600'
                        }`}>
                          <Icon className="h-5 w-5" />
                        </div>
                        
                        <div className="flex-1">
                          <div className="flex items-center space-x-2 mb-2">
                            <h4 className="font-medium text-gray-900">{insight.title}</h4>
                            <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                              insight.priority === 'high' ? 'bg-red-100 text-red-800' :
                              insight.priority === 'medium' ? 'bg-yellow-100 text-yellow-800' :
                              'bg-green-100 text-green-800'
                            }`}>
                              {insight.priority.toUpperCase()}
                            </span>
                            <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-800 capitalize">
                              {insight.type}
                            </span>
                          </div>
                          
                          <div className="text-sm text-gray-600 mb-3">
                            <strong>Evidence:</strong> {JSON.stringify(insight.evidence)}
                          </div>
                          
                          <div className="text-sm text-gray-800 mb-4">
                            <strong>Recommendation:</strong> {insight.recommendation}
                          </div>
                          
                          <div className="flex space-x-2">
                            <button
                              onClick={() => handleCreateNote(insight)}
                              disabled={createNoteMutation.isLoading}
                              className="flex items-center space-x-1 text-sm bg-blue-500 text-white px-3 py-1 rounded hover:bg-blue-600 disabled:opacity-50"
                            >
                              <Plus className="h-3 w-3" />
                              <span>Create Note</span>
                            </button>
                            
                            <button
                              onClick={() => handleAddToChecklist(insight)}
                              disabled={isInChecklist}
                              className={`flex items-center space-x-1 text-sm px-3 py-1 rounded ${
                                isInChecklist 
                                  ? 'bg-gray-100 text-gray-400 cursor-not-allowed' 
                                  : 'bg-green-500 text-white hover:bg-green-600'
                              }`}
                            >
                              {isInChecklist ? <CheckCircle className="h-3 w-3" /> : <Plus className="h-3 w-3" />}
                              <span>{isInChecklist ? 'Added' : 'Add to Checklist'}</span>
                            </button>
                          </div>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      </Card>

      {/* Checklist Panel */}
      {showChecklist && (
        <Card title="Marketing Action Checklist">
          <div className="space-y-4">
            {checklist.length === 0 ? (
              <p className="text-gray-500 text-center py-4">
                No items in checklist. Add insights above to build your action plan.
              </p>
            ) : (
              <>
                <div className="flex items-center justify-between">
                  <p className="text-sm text-gray-600">
                    {checklist.filter(item => item.completed).length} of {checklist.length} completed
                  </p>
                  <div className="flex space-x-2">
                    <button
                      onClick={copyChecklistToClipboard}
                      className="flex items-center space-x-1 text-sm bg-gray-500 text-white px-3 py-1 rounded hover:bg-gray-600"
                    >
                      <Copy className="h-3 w-3" />
                      <span>Copy</span>
                    </button>
                    <button
                      onClick={exportChecklistCSV}
                      className="flex items-center space-x-1 text-sm bg-blue-500 text-white px-3 py-1 rounded hover:bg-blue-600"
                    >
                      <Download className="h-3 w-3" />
                      <span>Export CSV</span>
                    </button>
                  </div>
                </div>

                <div className="space-y-2">
                  {checklist.map(item => (
                    <div key={item.id} className="flex items-center space-x-3 p-3 border rounded-lg">
                      <input
                        type="checkbox"
                        checked={item.completed}
                        onChange={() => handleToggleTaskComplete(item.id)}
                        className="w-4 h-4 text-blue-600"
                      />
                      <div className="flex-1">
                        <div className={`font-medium ${item.completed ? 'line-through text-gray-500' : 'text-gray-900'}`}>
                          {item.label}
                        </div>
                        <div className={`text-sm ${item.completed ? 'line-through text-gray-400' : 'text-gray-600'}`}>
                          {item.details}
                        </div>
                      </div>
                      <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                        item.priority === 'high' ? 'bg-red-100 text-red-800' :
                        item.priority === 'medium' ? 'bg-yellow-100 text-yellow-800' :
                        'bg-green-100 text-green-800'
                      }`}>
                        {item.priority.toUpperCase()}
                      </span>
                      <button
                        onClick={() => handleRemoveFromChecklist(item.id)}
                        className="text-gray-400 hover:text-red-500"
                      >
                        <X className="h-4 w-4" />
                      </button>
                    </div>
                  ))}
                </div>
              </>
            )}
          </div>
        </Card>
      )}
    </div>
  );
};

export default MarketingStrategyAdvisor;
